transform_js:
const nodesObj = {};  const links = [];
rawData.rows.forEach(r => {
  if (!nodesObj[r.source]) nodesObj[r.source] = { id: r.source, name: r.source, connections: 0 };
  if (!nodesObj[r.target]) nodesObj[r.target] = { id: r.target, name: r.target, connections: 0 };
  nodesObj[r.source].connections++;
  nodesObj[r.target].connections++;
  links.push({ source: r.source, target: r.target });
});
const nodes = Object.values(nodesObj).map(n => {
    // Node size based on connections, making central hubs larger
    n.symbolSize = Math.max(15, n.connections * 7);
    // Disable dragging for all nodes
    n.draggable = false;
    return n;
});
transformedData = { nodes, links };

echarts_js:
option = {
  title: {
    text: 'Social Network (Force-Directed)',
    left: 'center'
  },
  tooltip: {},
  series: [
    {
      type: 'graph',
      layout: 'force',
      data: transformedData.nodes,
      links: transformedData.links,
      roam: false,
      label: {
        show: true,
        position: 'right',
        formatter: '{b}'
      },
      force: {
        repulsion: 150,
        edgeLength: [30, 80]
      },
      itemStyle: {
         color: '#5470c6',
         borderColor: '#fff',
         borderWidth: 1
      },
      lineStyle: {
        color: '#999',
        curveness: 0.1
      }
    }
  ]
};
